import {
  FidesOriginConfig,
  ApiResponse,
  ApiError,
  AddressRisk,
  RiskCheckOptions,
  BatchRiskCheckRequest,
  BatchRiskCheckResponse,
  Rule,
  RuleListOptions,
  RuleListResponse,
  CreateRuleRequest,
  UpdateRuleRequest,
  WebSocketOptions,
  FidesOriginClient as IFidesOriginClient
} from './types';
import { FidesOriginWebSocket } from './websocket';

/**
 * FidesOrigin API Client
 * 
 * Main client for interacting with FidesOrigin risk assessment API
 */
export class FidesOriginClient implements IFidesOriginClient {
  public readonly config: FidesOriginConfig;
  
  private defaultConfig: Partial<FidesOriginConfig> = {
    timeout: 30000,
    debug: false,
    headers: {}
  };

  constructor(config: FidesOriginConfig) {
    this.config = { ...this.defaultConfig, ...config };
    
    if (!this.config.baseUrl) {
      throw new FidesOriginError('baseUrl is required', 'CONFIG_ERROR');
    }
    
    // Normalize base URL (remove trailing slash)
    this.config.baseUrl = this.config.baseUrl.replace(/\/$/, '');
    
    this.log('debug', 'FidesOriginClient initialized', { baseUrl: this.config.baseUrl });
  }

  /**
   * Check risk for a single address
   * 
   * @example
   * ```typescript
   * const risk = await client.checkAddress('0x123...', { chain: 'ethereum' });
   * console.log(risk.risk.level); // 'low' | 'medium' | 'high' | 'critical'
   * ```
   */
  public async checkAddress(
    address: string, 
    options: RiskCheckOptions = {}
  ): Promise<AddressRisk> {
    this.validateAddress(address);
    
    const params = new URLSearchParams();
    if (options.chain) params.append('chain', options.chain);
    if (options.includeEntities) params.append('includeEntities', 'true');
    if (options.includeStats) params.append('includeStats', 'true');
    
    const url = `/api/v1/risk/address/${encodeURIComponent(address)}?${params.toString()}`;
    
    const response = await this.request<AddressRisk>('GET', url);
    return response.data;
  }

  /**
   * Check risk for multiple addresses in batch
   * 
   * @example
   * ```typescript
   * const result = await client.checkBatchAddresses({
   *   addresses: ['0x123...', '0x456...'],
   *   chain: 'ethereum'
   * });
   * ```
   */
  public async checkBatchAddresses(
    request: BatchRiskCheckRequest
  ): Promise<BatchRiskCheckResponse> {
    if (!request.addresses || request.addresses.length === 0) {
      throw new FidesOriginError('addresses array is required', 'VALIDATION_ERROR');
    }
    
    // Validate all addresses
    request.addresses.forEach(addr => this.validateAddress(addr));
    
    const response = await this.request<BatchRiskCheckResponse>(
      'POST', 
      '/api/v1/risk/batch',
      request
    );
    return response.data;
  }

  /**
   * List all rules
   */
  public async listRules(options: RuleListOptions = {}): Promise<RuleListResponse> {
    const params = new URLSearchParams();
    if (options.status) params.append('status', options.status);
    if (options.page) params.append('page', options.page.toString());
    if (options.limit) params.append('limit', options.limit.toString());
    
    const url = `/api/v1/rules?${params.toString()}`;
    
    const response = await this.request<RuleListResponse>('GET', url);
    return response.data;
  }

  /**
   * Get a specific rule by ID
   */
  public async getRule(ruleId: string): Promise<Rule> {
    if (!ruleId) {
      throw new FidesOriginError('ruleId is required', 'VALIDATION_ERROR');
    }
    
    const url = `/api/v1/rules/${encodeURIComponent(ruleId)}`;
    const response = await this.request<Rule>('GET', url);
    return response.data;
  }

  /**
   * Create a new rule
   */
  public async createRule(request: CreateRuleRequest): Promise<Rule> {
    this.validateCreateRuleRequest(request);
    
    const response = await this.request<Rule>('POST', '/api/v1/rules', request);
    return response.data;
  }

  /**
   * Update an existing rule
   */
  public async updateRule(ruleId: string, request: UpdateRuleRequest): Promise<Rule> {
    if (!ruleId) {
      throw new FidesOriginError('ruleId is required', 'VALIDATION_ERROR');
    }
    
    const url = `/api/v1/rules/${encodeURIComponent(ruleId)}`;
    const response = await this.request<Rule>('PATCH', url, request);
    return response.data;
  }

  /**
   * Delete a rule
   */
  public async deleteRule(ruleId: string): Promise<void> {
    if (!ruleId) {
      throw new FidesOriginError('ruleId is required', 'VALIDATION_ERROR');
    }
    
    const url = `/api/v1/rules/${encodeURIComponent(ruleId)}`;
    await this.request<void>('DELETE', url);
  }

  /**
   * Create a WebSocket connection for real-time updates
   */
  public createWebSocket(options: WebSocketOptions = {}): FidesOriginWebSocket {
    return new FidesOriginWebSocket(this.config, options);
  }

  // ============================================================================
  // Private Methods
  // ============================================================================

  private async request<T>(
    method: string,
    path: string,
    body?: unknown
  ): Promise<ApiResponse<T>> {
    const url = `${this.config.baseUrl}${path}`;
    
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      ...this.config.headers
    };
    
    if (this.config.apiKey) {
      headers['Authorization'] = `Bearer ${this.config.apiKey}`;
    }
    
    const fetchOptions: RequestInit = {
      method,
      headers,
      signal: AbortSignal.timeout(this.config.timeout || 30000)
    };
    
    if (body && method !== 'GET' && method !== 'HEAD') {
      fetchOptions.body = JSON.stringify(body);
    }
    
    this.log('debug', 'API Request', { method, url });
    
    try {
      const response = await fetch(url, fetchOptions);
      
      if (!response.ok) {
        await this.handleErrorResponse(response);
      }
      
      const data = await response.json() as T;
      
      this.log('debug', 'API Response', { status: response.status, url });
      
      return {
        data,
        status: response.status
      };
    } catch (error) {
      if (error instanceof FidesOriginError) {
        throw error;
      }
      
      if (error instanceof TypeError && error.message.includes('fetch')) {
        throw new FidesOriginError(
          'Network error. Please check your connection.',
          'NETWORK_ERROR',
          { originalError: error.message }
        );
      }
      
      if (error instanceof DOMException && error.name === 'AbortError') {
        throw new FidesOriginError(
          'Request timeout. Please try again.',
          'TIMEOUT_ERROR',
          { timeout: this.config.timeout }
        );
      }
      
      throw new FidesOriginError(
        'An unexpected error occurred',
        'UNKNOWN_ERROR',
        { originalError: String(error) }
      );
    }
  }

  private async handleErrorResponse(response: Response): Promise<never> {
    let errorData: Partial<ApiError> = {};
    
    try {
      errorData = await response.json();
    } catch {
      // If JSON parsing fails, use status text
      errorData = {
        code: `HTTP_${response.status}`,
        message: response.statusText
      };
    }
    
    throw new FidesOriginError(
      errorData.message || `HTTP Error ${response.status}`,
      errorData.code || `HTTP_${response.status}`,
      errorData.details,
      response.status
    );
  }

  private validateAddress(address: string): void {
    if (!address || typeof address !== 'string') {
      throw new FidesOriginError('Address is required', 'VALIDATION_ERROR');
    }
    
    // Basic address format validation
    const ethereumPattern = /^0x[a-fA-F0-9]{40}$/;
    const bitcoinPattern = /^(bc1|[13])[a-zA-HJ-NP-Z0-9]{25,62}$/;
    
    if (!ethereumPattern.test(address) && !bitcoinPattern.test(address)) {
      throw new FidesOriginError(
        `Invalid address format: ${address}`,
        'VALIDATION_ERROR',
        { address }
      );
    }
  }

  private validateCreateRuleRequest(request: CreateRuleRequest): void {
    if (!request.name || typeof request.name !== 'string') {
      throw new FidesOriginError('Rule name is required', 'VALIDATION_ERROR');
    }
    
    if (!Array.isArray(request.conditions) || request.conditions.length === 0) {
      throw new FidesOriginError('At least one condition is required', 'VALIDATION_ERROR');
    }
    
    if (!Array.isArray(request.actions) || request.actions.length === 0) {
      throw new FidesOriginError('At least one action is required', 'VALIDATION_ERROR');
    }
    
    // Validate conditions
    request.conditions.forEach((condition, index) => {
      if (!condition.field) {
        throw new FidesOriginError(
          `Condition ${index + 1}: field is required`,
          'VALIDATION_ERROR'
        );
      }
      if (!condition.operator) {
        throw new FidesOriginError(
          `Condition ${index + 1}: operator is required`,
          'VALIDATION_ERROR'
        );
      }
    });
    
    // Validate actions
    request.actions.forEach((action, index) => {
      if (!action.type) {
        throw new FidesOriginError(
          `Action ${index + 1}: type is required`,
          'VALIDATION_ERROR'
        );
      }
      
      const validTypes = ['flag', 'block', 'review', 'allow'];
      if (!validTypes.includes(action.type)) {
        throw new FidesOriginError(
          `Action ${index + 1}: invalid type. Must be one of: ${validTypes.join(', ')}`,
          'VALIDATION_ERROR'
        );
      }
    });
  }

  private log(level: 'debug' | 'info' | 'warn' | 'error', message: string, meta?: Record<string, unknown>): void {
    if (!this.config.debug && level === 'debug') return;
    
    const timestamp = new Date().toISOString();
    const logMessage = `[${timestamp}] [${level.toUpperCase()}] [FidesOrigin] ${message}`;
    
    if (meta) {
      console.log(logMessage, meta);
    } else {
      console.log(logMessage);
    }
  }
}

/**
 * FidesOrigin SDK Error Class
 */
export class FidesOriginError extends Error {
  public readonly code: string;
  public readonly details?: Record<string, unknown>;
  public readonly status?: number;

  constructor(
    message: string,
    code: string,
    details?: Record<string, unknown>,
    status?: number
  ) {
    super(message);
    this.name = 'FidesOriginError';
    this.code = code;
    this.details = details;
    this.status = status;
    
    // Maintain proper stack trace in V8 environments
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, FidesOriginError);
    }
  }

  toJSON(): Record<string, unknown> {
    return {
      name: this.name,
      message: this.message,
      code: this.code,
      details: this.details,
      status: this.status
    };
  }
}

export { FidesOriginWebSocket } from './websocket';
export * from './types';
